sql:
SELECT COUNT(review_id) AS shining_stars
FROM exhibition_reviews
WHERE rating >= 4;

SELECT title 
FROM exhibitions 
WHERE attendance = (SELECT MAX(attendance) FROM exhibitions);

SELECT exhibition_id, COUNT(DISTINCT visitor_id) AS unique_total_visitors
FROM exhibition_visitors
GROUP BY exhibition_id;

external_knowledge:
- "Unique visitors" refers to the number of distinct individuals who have visited the exhibition;
- "Total spending" is the sum of all expenditures made for the exhibition;
- "Average rating" is calculated by summing all the ratings and dividing by the number of reviews.

- "tales of the exhibitions" refers to the details of the exhibitions, such as the title and visit date;
- "curious souls" refers to the visitors;
- "day they visited" refers to the visit date;
- "their names" refers to the visitor names;
- "nature of their visit" refers to the visit type;
- "wandered through the halls" refers to the visits;
- "how many times" refers to the total number of visits.

sql:
SELECT MAX(attendance) AS max_attendance
FROM exhibitions
WHERE theme = 'Modern Art';

SELECT title, start_date, end_date, location_id, status
FROM exhibitions
ORDER BY start_date DESC;

external_knowledge:
- "masterpiece stands out as the gem" refers to the artwork with the highest average rating;
- "earning the highest praise from visitors" refers to the highest average rating given by visitors;
- "for each showcase" refers to each exhibition.

- "Masterpieces" refers to exhibitions;
- "Garnished the most admiration" refers to having a higher average rating than the overall average rating of all exhibitions;
- "Shining brighter than the average star" is a metaphor for an exhibition's average rating being above the average rating of all exhibitions;
- "Top 5" means the query returns the five exhibitions with the highest average ratings.

sql:
SELECT title
FROM exhibitions
WHERE attendance = (SELECT MAX(attendance) FROM exhibitions);

external_knowledge:
- Reviews with more helpful votes are generally considered more reliable by visitors;
- The average rating gives an overall impression of the exhibition's quality;
- The number of distinct visitors indicates the reach and popularity of the exhibition.

- "Exhibitions" are events or displays of art, artifacts, or other items of cultural or historical interest;
- "Visitor count" is the number of people who have attended the exhibition;
- "Average rating" is the mean score given by visitors, usually on a scale from 1 to 5 stars.

- "blossomed with more than 10 reviews" refers to exhibitions that have received more than 10 reviews;
- "unique visitors" refers to distinct visitors, ensuring each visitor is counted only once regardless of the number of visits;
- "average star ratings" is the mean rating given by visitors, calculated by summing all ratings and dividing by the number of ratings.

- 'Completed exhibition' refers to an exhibition that has ended and is marked as 'completed' in the database;
- 'Highest praise' is determined by the average rating given by visitors, where a higher average rating indicates more positive feedback;
- 'Average rating' is calculated by taking the mean of all ratings for a given exhibition.

sql:
SELECT title, status
FROM exhibitions
ORDER BY title ASC;

SELECT exhibition_id, title, attendance
FROM exhibitions
ORDER BY attendance DESC;

SELECT exhibition_id, COUNT(visitor_id) AS visitor_count
FROM exhibition_visitors
GROUP BY exhibition_id;
